  .mrg-ai-chat-workspace [data-slot="ai-chat-workspace-sidebar"] {
    padding: var(--mrg-semantic-density-panel-padding);
    border-inline-end: var(--mrg-semantic-border-width-default) solid
      var(--mrg-semantic-color-border-strong);
