    display: grid;
    gap: var(--mrg-semantic-space-stack-xs);
    padding: 0;
    margin: 0;
    list-style: none;
  }

  .mrg-ai-chat-workspace [data-slot="ai-chat-workspace-sidebar"] button {
    inline-size: 100%;
    min-block-size: var(--mrg-semantic-size-target-minimum);
